setIsPostpress:
function setIsPostpress(ppType) {

		if (ppType == "osi") { //오시
			product1.ppOsi();
		} else if (ppType == "missing") { //미싱
			product1.ppMissing();
		} else if (ppType == "domusong") { //도무송
			if ($('chk_is_epoxy').checked == true) {
				product1.ppEpoxy(); //도무송이 선택되면 에폭시 사이즈가 도무송 사이즈로 변함//
			}
			product1.ppDomusong();

		} else if (ppType == "bak") { //박
			product1.ppBak('1');
		} else if (ppType == "ap") { //형압
			product1.ppAP('1');
		} else if (ppType == "numbering") { //넘버링
			product1.ppNumbering();
		} else if (ppType == "tagong") { //타공
			product1.ppTagong();
		} else if (ppType == "guidori") { //귀도리
			product1.ppGuidori();
		} else if (ppType == "epoxy") { //에폭시
			product1.ppEpoxy();
		}else if (ppType == "dbak") { //디지털박
			product1.ppDBak('1');
		}

	}
